import {useEffect, useState} from "react";

import {DisplayConfig} from './Config';

import './displays.css';
import Match from "./pages/Match";
import Primary from "./layouts/Primary";
import {initialConfig} from "./displayContainer";
import {DisplayCommandType} from "../javaTypes";
import {DisplayParamsType} from "./DisplayParams";
import {PermissiveURLSearchParams} from "../utils";
import DisplayErrorBoundary from "./DisplayErrorBoundary";

const searchParams = new URLSearchParams(window.location.search);
const valueFromQuery = Object.assign({}, initialConfig, { fieldStyleTimer: true });
searchParams.forEach((value : string | boolean, key) => {
    if(value === 'true') {
        value = true;
    }
    if(value === 'false') {
        value = false;
    }
    // Query params inherently can't be usefully typed; just assume they came in correctly
    // @ts-ignore
    valueFromQuery[key] = value;
})
console.log(valueFromQuery)
export default function TimerContainer({} : DisplayParamsType){
    const [config, setConfig] = useState(valueFromQuery);
    const [dimensions, setDimensions] = useState({
        height: window.innerHeight,
        width: window.innerWidth
    })
    const [command, setCommand] = useState({
        type: DisplayCommandType.SHOW_MATCH,
        ts: Date.now(),
        index: -1,
        field: 0,
        init: true,
        params: { _empty: true }
    })
    function updateConfig(newConfig : DisplayConfig) {
        setConfig(newConfig);
        window.history.replaceState({}, '', window.location.pathname + '?' + PermissiveURLSearchParams({...newConfig}).toString())
    }

    useEffect(() => {
        function handleResize() {
            setDimensions({
                height: window.innerHeight,
                width: window.innerWidth
            })
        }

        const listener = function (e : KeyboardEvent) {
            if(e.code === 'Space' || e.which === 32) {
                setCommand((was) => {
                    if(was.type === DisplayCommandType.START_MATCH && (Date.now() - was.ts) < 1000 * (120 + 30 + 8)) {
                        return was;
                    }
                    return {
                        type: DisplayCommandType.START_MATCH,
                        ts: Date.now(),
                        index: -1,
                        field: 0,
                        init: false,
                        params: { _empty: true }
                    }
                })
            } else if(e.code === 'Escape' || e.which === 27) {
                setCommand((was) => {
                    if(was.type !== DisplayCommandType.START_MATCH || (Date.now() - was.ts) > 1000 * (120 + 30 + 8)) {
                        return was;
                    }
                    return {
                        type: DisplayCommandType.ABORT_MATCH,
                        ts: Date.now(),
                        index: -1,
                        field: 0,
                        init: false,
                        params: { _empty: true }
                    }
                })
            }
        }
        document.addEventListener('keydown', listener);

        window.addEventListener('resize', handleResize)

        return () => {
            document.removeEventListener("keydown", listener)
            window.removeEventListener('resize', handleResize)
        }
    }, [])

    const nowCallback = Date.now

    const xZoom = dimensions.width / 1920;
    const yZoom = dimensions.height / 1080;
    const displayScale = Math.min(xZoom, yZoom);
    return <div style={{ "--display-scale": displayScale }}>
        {/*<Config config={config} setConfig={updateConfig}isConfigured={!window.location.search} style={'timerOnly'} />*/}
        <div className="displayContainer">
            <DisplayErrorBoundary>
                <Match command={command} config={config} nowCallback={nowCallback} timerOnly />
            </DisplayErrorBoundary>
        </div>
    </div>
}