import TimerContainer from './timerContainer'
import AssetHelper from "../AssetHelper";
import {initSounds} from "../sounds";
import {preloadVideos} from "./components/MatchVideo";
import { createRoot } from "react-dom/client";

// useAsset already handles ensuring this is loaded, but to allow preloading a/v clips it's much easier to
// not be forced to work with async apis
AssetHelper.ensureProperties().then(() => {
    initSounds();
    preloadVideos();
    const target = document.getElementById('displayRoot');
    if(!target) {
        throw "Target element for display not found"
    }
    const root = createRoot(target)
    root.render(<TimerContainer {...window.displayParams} />);
})
